import urllib.request, json, re

base = 'http://localhost:80/wp-json/wp/v2'
endpoints = ['posts','pages','media','comments','categories','tags']
pattern = re.compile(r'flag\{[^}]*\}', re.IGNORECASE)
found = []

def fetch(url):
    try:
        with urllib.request.urlopen(url, timeout=10) as r:
            data = r.read()
            try:
                return json.loads(data.decode())
            except Exception:
                return data.decode(errors='ignore')
    except Exception as e:
        return {'error': str(e), 'url': url}

for ep in endpoints:
    page = 1
    while True:
        url = f"{base}/{ep}?per_page=100&page={page}"
        data = fetch(url)
        if isinstance(data, dict) and 'error' in data:
            break
        if not isinstance(data, list) or not data:
            break
        for item in data:
            text = json.dumps(item)
            for m in pattern.finditer(text):
                found.append({'endpoint': ep, 'page': page, 'id': item.get('id'), 'match': m.group(0), 'url': item.get('link') or item.get('source_url')})
        page += 1

print(json.dumps(found, indent=2))

